(function(){
const admin=JSON.parse(localStorage.getItem("stockprimeAdminSession")||"null");if(!admin){location.replace("admin-login.html");return}
const body=document.body,content=document.querySelector("#admin-content"),title=document.querySelector("[data-admin-title]"),modal=document.querySelector("[data-admin-modal]"),toast=document.querySelector("[data-admin-toast]");
const keys={vehicles:"adminVehicles",plans:"adminInvestmentPlans",audit:"adminAuditLog",users:"adminUsers",payments:"adminPayments"};
const seedPlans=[{id:"PLAN-001",name:"Tesla Growth Fund",category:"Tesla-Focused",nav:35.5,minInvestment:100,risk:"High",returnRate:9.23,status:"Active"},{id:"PLAN-002",name:"Sustainable Energy ETF",category:"ESG",nav:18.75,minInvestment:50,risk:"Medium",returnRate:4.8,status:"Active"},{id:"PLAN-003",name:"Global Growth Fund",category:"Growth",nav:19.8,minInvestment:400,risk:"Medium",returnRate:6.4,status:"Active"}];
const seedVehicles=[{id:"VEH-MODEL-Y",title:"2026 Model Y Long Range",vin:"TESLAY2026LR0001",year:2026,make:"Tesla",model:"Model Y Long Range",mileage:18,price:52990,status:"Available",color:"Ultra Red",fuel:"Electric",image:"images/Homepage-Promo-Meet-Model-Y-Desktop.avif",description:"Long-range electric SUV with flexible seating and advanced safety.",minDeposit:10,featured:true},{id:"VEH-CYBERTRUCK",title:"2026 Cybertruck AWD",vin:"TESLACYBER260001",year:2026,make:"Tesla",model:"Cybertruck AWD",mileage:12,price:99990,status:"Available",color:"Stainless Steel",fuel:"Electric",image:"images/Cybertruck-Terrain-Badge-Desktop-NA-SA-APAC.avif",description:"All-wheel-drive utility vehicle with adaptive air suspension.",minDeposit:10,featured:true},{id:"VEH-MODEL-3",title:"2025 Model 3 Performance",vin:"TESLA3P20250001",year:2025,make:"Tesla",model:"Model 3 Performance",mileage:85,price:54990,status:"Available",color:"Pearl White",fuel:"Electric",image:"images/tesla-hero.jpg",description:"Performance-focused electric sedan with premium interior.",minDeposit:15,featured:true}];const get=(key,fallback=[])=>{try{return JSON.parse(localStorage.getItem(key)||JSON.stringify(fallback))}catch{return fallback}},set=(key,value)=>localStorage.setItem(key,JSON.stringify(value)),money=n=>Number(n||0).toLocaleString("en-US",{style:"currency",currency:"USD"});
if(!localStorage.getItem(keys.vehicles))set(keys.vehicles,seedVehicles);if(!localStorage.getItem(keys.plans))set(keys.plans,seedPlans);if(!localStorage.getItem(keys.audit))set(keys.audit,[{id:crypto.randomUUID(),action:"Admin session started",target:admin.email,admin:admin.name,time:new Date().toISOString()}]);
function audit(action,target){const logs=get(keys.audit);logs.unshift({id:crypto.randomUUID(),action,target,admin:admin.name,time:new Date().toISOString()});set(keys.audit,logs.slice(0,250))}
function showToast(message){toast.textContent=message;toast.classList.add("show");clearTimeout(window.at);window.at=setTimeout(()=>toast.classList.remove("show"),2300)}
const escapeHtml=value=>String(value??"").replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[c]));
const status=s=>`<span class="status-pill ${String(s).toLowerCase().replaceAll(" ","-")}">${escapeHtml(s)}</span>`;
const wrapper=inner=>`<div class="admin-container">${inner}</div>`;
function aggregateOrders(){const vehicle=get("vehicleOrders"),invest=get("pendingInvestments"),stock=get("stockOrders");return [...vehicle.map((o,i)=>({id:o.id||`VEH-${String(i+1).padStart(3,"0")}`,type:"Vehicle",item:o.vehicle,customer:o.customer||"Current customer",amount:o.deposit||0,status:o.status||"Draft",date:o.createdAt})),...invest.map((o,i)=>({id:`INV-${String(i+1).padStart(3,"0")}`,type:"Investment",item:o.plan,customer:"Current customer",amount:o.amount||0,status:o.status||"Processing",date:o.createdAt,source:"pendingInvestments",sourceIndex:i})),...stock.map((o,i)=>({id:`STK-${String(i+1).padStart(3,"0")}`,type:"Stock",item:`${o.shares} × ${o.symbol}`,customer:"Current customer",amount:(o.shares||0)*(o.price||0),status:o.status||"Processing",date:o.createdAt,source:"stockOrders",sourceIndex:i}))]}
function getUsers(){let users=get(keys.users);if(!users.length){const session=JSON.parse(localStorage.getItem("stockprimeSession")||"null"),profile=JSON.parse(localStorage.getItem("stockprimeProfile")||"null");if(session)users=[{id:"USR-001",name:profile?.name||session.name||"Customer",email:profile?.email||session.email,status:"Active",kyc:localStorage.getItem("kycSubmission")?"Pending":"Not Submitted",joined:session.signedInAt||new Date().toISOString()}];set(keys.users,users)}return users}
function overview(){
 const vehicles=get(keys.vehicles),plans=get(keys.plans),users=getUsers(),orders=aggregateOrders(),kyc=localStorage.getItem("kycSubmission")?1:0,logs=get(keys.audit);
 content.innerHTML=wrapper(`<div class="admin-welcome"><div><h1>Good ${new Date().getHours()<12?"morning":new Date().getHours()<18?"afternoon":"evening"}, ${escapeHtml(admin.name)}</h1><p>Here’s what is happening across the platform.</p></div><div class="admin-date">${new Date().toLocaleDateString(undefined,{weekday:"long",month:"long",day:"numeric",year:"numeric"})}</div></div><section class="metric-grid">${metric("Total Users",users.length,"♙","+0 this month")}${metric("Active Vehicles",vehicles.filter(v=>v.status==="Available").length,"⌁",`${vehicles.length} total records`)}${metric("Open Orders",orders.filter(o=>!["Completed","Cancelled","Rejected"].includes(o.status)).length,"▣",`${orders.length} total orders`)}${metric("Pending KYC",kyc,"◇",kyc?"Requires review":"All caught up")}</section><section class="admin-grid"><article class="admin-card"><div class="admin-card-head"><div><h2>Operations activity</h2><p>Latest administrative changes</p></div><button class="admin-secondary" data-go="audit">View all</button></div><div class="admin-card-body activity-list">${logs.slice(0,6).map(l=>`<div class="activity"><i>•</i><div><b>${escapeHtml(l.action)}</b><span>${escapeHtml(l.target)}</span></div><time>${timeAgo(l.time)}</time></div>`).join("")||'<div class="table-empty">No activity yet</div>'}</div></article><article class="admin-card"><div class="admin-card-head"><div><h2>Quick actions</h2><p>Common operations</p></div></div><div class="admin-card-body quick-grid"><button class="quick-action" data-add-vehicle><i>＋</i><b>Add vehicle</b><span>Create inventory record</span></button><button class="quick-action" data-add-plan><i>↗</i><b>Add plan</b><span>Configure investment</span></button><button class="quick-action" data-go="kyc"><i>◇</i><b>Review KYC</b><span>Identity submissions</span></button><button class="quick-action" data-go="orders"><i>▣</i><b>Manage orders</b><span>Approvals and status</span></button></div></article></section><section class="admin-card" style="margin-top:18px"><div class="admin-card-head"><div><h2>Platform activity</h2><p>Orders created over the last seven days</p></div></div><div class="bar-chart">${[22,42,28,67,48,82,55].map((h,i)=>`<div class="bar" style="height:${h}%"><span>${["Mon","Tue","Wed","Thu","Fri","Sat","Sun"][i]}</span></div>`).join("")}</div></section>`);
 bindGo();content.querySelector("[data-add-vehicle]").onclick=()=>vehicleModal();content.querySelector("[data-add-plan]").onclick=()=>planModal();
}
function metric(label,value,icon,sub){return `<article class="metric"><div class="metric-head"><span>${label}</span><i class="metric-icon">${icon}</i></div><strong>${value}</strong><small>${sub}</small></article>`}
function toolbar(name,button,label="Add New"){return `<div class="section-toolbar"><h1>${name}</h1><input class="admin-search" data-table-search placeholder="Search records…"><button class="admin-primary" ${button}>＋ ${label}</button></div>`}
function vehicles(){
 const records=get(keys.vehicles);content.innerHTML=wrapper(`${toolbar("Vehicle Inventory","data-add-vehicle","Add Vehicle")}<div class="admin-filters" style="margin-bottom:12px"><select data-status-filter><option value="">All statuses</option>${["Available","Reserved","Financing In Progress","Sold","Delivered","Archived"].map(x=>`<option>${x}</option>`)}</select></div><section class="admin-table-card"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>VEHICLE</th><th>VIN</th><th>YEAR</th><th>PRICE</th><th>MILEAGE</th><th>STATUS</th><th>ACTIONS</th></tr></thead><tbody data-vehicle-rows></tbody></table></div></section>`);
 const renderRows=()=>{const q=content.querySelector("[data-table-search]").value.toLowerCase(),sf=content.querySelector("[data-status-filter]").value,filtered=get(keys.vehicles).filter(v=>(v.title.toLowerCase().includes(q)||v.vin.toLowerCase().includes(q))&&(!sf||v.status===sf));content.querySelector("[data-vehicle-rows]").innerHTML=filtered.length?filtered.map(v=>`<tr><td><div class="table-title">${escapeHtml(v.title)}</div><div class="table-sub">${escapeHtml(v.make)} ${escapeHtml(v.model)} • ${escapeHtml(v.color)}</div></td><td>${escapeHtml(v.vin)}</td><td>${v.year}</td><td>${money(v.price)}</td><td>${Number(v.mileage||0).toLocaleString()} mi</td><td>${status(v.status)}</td><td><div class="table-actions"><button data-edit-vehicle="${v.id}">Edit</button><button data-delete-vehicle="${v.id}">Delete</button></div></td></tr>`).join(""):`<tr><td colspan="7"><div class="table-empty"><i>⌁</i>No vehicle records found. Add your first vehicle.</div></td></tr>`;bindVehicleRows()};
 content.querySelector("[data-add-vehicle]").onclick=()=>vehicleModal();content.querySelector("[data-table-search]").oninput=renderRows;content.querySelector("[data-status-filter]").onchange=renderRows;renderRows();
 function bindVehicleRows(){content.querySelectorAll("[data-edit-vehicle]").forEach(b=>b.onclick=()=>vehicleModal(get(keys.vehicles).find(v=>v.id===b.dataset.editVehicle)));content.querySelectorAll("[data-delete-vehicle]").forEach(b=>b.onclick=()=>confirmDelete("vehicle",b.dataset.deleteVehicle))}
}
function vehicleModal(record){
 const edit=!!record;openModal(`${edit?"Edit":"Add"} Vehicle`, `<form class="admin-form" data-record-form><div class="admin-form-grid"><label class="admin-field"><span>Vehicle title</span><input name="title" required value="${escapeHtml(record?.title||"")}"></label><label class="admin-field"><span>VIN</span><input name="vin" required value="${escapeHtml(record?.vin||"")}"></label><label class="admin-field"><span>Year</span><input name="year" type="number" min="1990" max="2035" required value="${record?.year||2026}"></label><label class="admin-field"><span>Make</span><input name="make" required value="${escapeHtml(record?.make||"Tesla")}"></label><label class="admin-field"><span>Model</span><input name="model" required value="${escapeHtml(record?.model||"")}"></label><label class="admin-field"><span>Mileage</span><input name="mileage" type="number" min="0" value="${record?.mileage||0}"></label><label class="admin-field"><span>Price</span><input name="price" type="number" min="1" step=".01" required value="${record?.price||""}"></label><label class="admin-field"><span>Status</span><select name="status">${["Available","Reserved","Financing In Progress","Sold","Delivered","Archived"].map(x=>`<option ${record?.status===x?"selected":""}>${x}</option>`)}</select></label><label class="admin-field"><span>Exterior color</span><input name="color" value="${escapeHtml(record?.color||"")}"></label><label class="admin-field"><span>Fuel type</span><select name="fuel"><option>Electric</option><option>Hybrid</option><option>Gasoline</option></select></label><label class="admin-field wide"><span>Image URL or local path</span><input name="image" value="${escapeHtml(record?.image||"images/tesla-model-y.jpg")}"></label><label class="admin-field wide"><span>Description</span><textarea name="description">${escapeHtml(record?.description||"")}</textarea></label><label class="admin-field"><span>Minimum deposit %</span><input name="minDeposit" type="number" min="0" max="100" value="${record?.minDeposit??30}"></label><label class="admin-field"><span>Featured</span><select name="featured"><option value="false">No</option><option value="true" ${record?.featured?"selected":""}>Yes</option></select></label></div><div class="admin-form-error"></div><div class="admin-form-actions"><button type="button" class="admin-secondary" data-modal-close>Cancel</button><button class="admin-primary">Save Vehicle</button></div></form>`);
 const form=modal.querySelector("[data-record-form]");form.onsubmit=e=>{e.preventDefault();const records=get(keys.vehicles),data=Object.fromEntries(new FormData(form));data.id=record?.id||`VEH-${Date.now()}`;data.year=Number(data.year);data.mileage=Number(data.mileage);data.price=Number(data.price);data.minDeposit=Number(data.minDeposit);data.featured=data.featured==="true";data.updatedAt=new Date().toISOString();if(edit)records[records.findIndex(v=>v.id===record.id)]=data;else records.unshift(data);set(keys.vehicles,records);audit(`${edit?"Updated":"Created"} vehicle`,data.title);closeModal();showToast(`Vehicle ${edit?"updated":"created"} successfully`);vehicles()};bindModalClose();
}
async function plans(){
 content.innerHTML=wrapper(`${toolbar("Investment Plans","data-add-plan","Add Plan")}<section class="admin-table-card"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>PLAN</th><th>CATEGORY</th><th>NAV</th><th>MINIMUM</th><th>RETURN</th><th>RISK</th><th>STATUS</th><th>ACTIONS</th></tr></thead><tbody data-plan-rows><tr><td colspan="8"><div class="table-empty">Loading plans...</div></td></tr></tbody></table></div></section>`);
 const rowsHost=content.querySelector("[data-plan-rows]"),search=content.querySelector("[data-table-search]");let records=[];
 const normalize=p=>({id:p.public_id,name:p.name,category:p.category,nav:Number(p.nav_cents)/100,minInvestment:Number(p.minimum_cents)/100,returnRate:Number(p.projected_return_bps)/100,managementFee:Number(p.management_fee_bps)/100,risk:p.risk_level,status:p.status==="active"?"Active":"Inactive",description:p.description||""});
 const renderRows=()=>{const q=search.value.toLowerCase(),rows=records.filter(p=>p.name.toLowerCase().includes(q)||p.category.toLowerCase().includes(q));rowsHost.innerHTML=rows.length?rows.map(p=>`<tr><td><div class="table-title">${escapeHtml(p.name)}</div><div class="table-sub">${escapeHtml(p.id)}</div></td><td>${escapeHtml(p.category)}</td><td>${money(p.nav)}</td><td>${money(p.minInvestment)}</td><td class="positive">+${p.returnRate.toFixed(2)}%</td><td>${escapeHtml(p.risk)}</td><td>${status(p.status)}</td><td><div class="table-actions"><button data-edit-plan="${escapeHtml(p.id)}">Edit</button><button data-delete-plan="${escapeHtml(p.id)}">Deactivate</button></div></td></tr>`).join(""):`<tr><td colspan="8"><div class="table-empty">No investment plans found.</div></td></tr>`;rowsHost.querySelectorAll("[data-edit-plan]").forEach(b=>b.onclick=()=>planModal(records.find(p=>p.id===b.dataset.editPlan)));rowsHost.querySelectorAll("[data-delete-plan]").forEach(b=>b.onclick=()=>deletePlan(b.dataset.deletePlan))};
 const load=async()=>{try{const response=await fetch("/api/admin/investment-plans",{credentials:"same-origin"}),data=await response.json();if(response.status===401){localStorage.removeItem("stockprimeAdminSession");location.replace("admin-login.html");return}if(!response.ok)throw new Error(data.error||"Plans could not be loaded.");records=(data.plans||[]).map(normalize);renderRows()}catch(error){rowsHost.innerHTML=`<tr><td colspan="8"><div class="table-empty">${escapeHtml(error.message)}</div></td></tr>`}};
 const deletePlan=async id=>{try{const response=await fetch(`/api/admin/investment-plans/${encodeURIComponent(id)}`,{method:"DELETE",credentials:"same-origin"}),data=await response.json();if(!response.ok)throw new Error(data.error||"Plan could not be deactivated.");showToast(data.message);load()}catch(error){showToast(error.message)}};
 content.querySelector("[data-add-plan]").onclick=()=>planModal();search.oninput=renderRows;load();
}
function planModal(record){
 const edit=!!record;openModal(`${edit?"Edit":"Add"} Investment Plan`,`<form class="admin-form" data-record-form><div class="admin-form-grid"><label class="admin-field wide"><span>Plan name</span><input name="name" required value="${escapeHtml(record?.name||"")}"></label><label class="admin-field"><span>Category</span><input name="category" required value="${escapeHtml(record?.category||"")}"></label><label class="admin-field"><span>Current NAV</span><input name="nav" type="number" min="0" step=".0001" required value="${record?.nav||""}"></label><label class="admin-field"><span>Minimum investment</span><input name="minInvestment" type="number" min="1" required value="${record?.minInvestment||""}"></label><label class="admin-field"><span>Projected return %</span><input name="returnRate" type="number" step=".01" value="${record?.returnRate??70}"></label><label class="admin-field"><span>Risk level</span><select name="risk">${["Low","Medium","High"].map(x=>`<option ${record?.risk===x?"selected":""}>${x}</option>`)}</select></label><label class="admin-field"><span>Management fee %</span><input name="managementFee" type="number" min="0" step=".01" value="${record?.managementFee??0.85}"></label><label class="admin-field"><span>Status</span><select name="status"><option ${record?.status!=="Inactive"?"selected":""}>Active</option><option ${record?.status==="Inactive"?"selected":""}>Inactive</option></select></label><label class="admin-field wide"><span>Description</span><textarea name="description">${escapeHtml(record?.description||"")}</textarea></label></div><div class="admin-form-actions"><button type="button" class="admin-secondary" data-modal-close>Cancel</button><button class="admin-primary">Save Plan</button></div></form>`);
 const form=modal.querySelector("form");form.onsubmit=async e=>{e.preventDefault();const submit=form.querySelector(".admin-primary"),data=Object.fromEntries(new FormData(form));data.id=record?.id||"";["nav","minInvestment","returnRate","managementFee"].forEach(k=>data[k]=Number(data[k]));submit.disabled=true;submit.textContent="Saving...";try{const response=await fetch("/api/admin/investment-plans",{method:"POST",headers:{"Content-Type":"application/json"},credentials:"same-origin",body:JSON.stringify(data)}),result=await response.json();if(!response.ok)throw new Error(result.error||"Plan could not be saved.");audit(`${edit?"Updated":"Created"} investment plan`,data.name);closeModal();showToast(result.message);plans()}catch(error){showToast(error.message);submit.disabled=false;submit.textContent="Save Plan"}};bindModalClose();
}
function users(){
 const records=getUsers();content.innerHTML=wrapper(`${toolbar("User Management","data-add-user","Create User")}<section class="admin-table-card"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>USER</th><th>EMAIL</th><th>KYC</th><th>STATUS</th><th>JOINED</th><th>ACTIONS</th></tr></thead><tbody>${records.map(u=>`<tr><td><div class="table-title">${escapeHtml(u.name)}</div><div class="table-sub">${u.id}</div></td><td>${escapeHtml(u.email)}</td><td>${status(u.kyc)}</td><td>${status(u.status)}</td><td>${new Date(u.joined).toLocaleDateString()}</td><td><div class="table-actions"><button data-toggle-user="${u.id}">${u.status==="Active"?"Suspend":"Activate"}</button><button data-delete-user="${u.id}">Delete</button></div></td></tr>`).join("")||'<tr><td colspan="6"><div class="table-empty">No users found.</div></td></tr>'}</tbody></table></div></section>`);content.querySelector("[data-add-user]").onclick=userModal;content.querySelectorAll("[data-toggle-user]").forEach(b=>b.onclick=()=>{const users=getUsers(),u=users.find(x=>x.id===b.dataset.toggleUser);u.status=u.status==="Active"?"Suspended":"Active";set(keys.users,users);audit(`${u.status} user`,u.email);showToast(`User ${u.status.toLowerCase()}`);usersView()});content.querySelectorAll("[data-delete-user]").forEach(b=>b.onclick=()=>confirmDelete("user",b.dataset.deleteUser));
}
const usersView=users;
function userModal(){openModal("Create User",`<form class="admin-form"><div class="admin-form-grid"><label class="admin-field"><span>Full name</span><input name="name" required></label><label class="admin-field"><span>Email</span><input type="email" name="email" required></label><label class="admin-field"><span>Status</span><select name="status"><option>Active</option><option>Suspended</option></select></label><label class="admin-field"><span>KYC state</span><select name="kyc"><option>Not Submitted</option><option>Pending</option><option>Approved</option><option>Rejected</option></select></label></div><div class="admin-form-actions"><button type="button" class="admin-secondary" data-modal-close>Cancel</button><button class="admin-primary">Create User</button></div></form>`);const form=modal.querySelector("form");form.onsubmit=e=>{e.preventDefault();const users=getUsers(),data=Object.fromEntries(new FormData(form));data.id=`USR-${Date.now()}`;data.joined=new Date().toISOString();users.unshift(data);set(keys.users,users);audit("Created user",data.email);closeModal();showToast("User created successfully");usersView()};bindModalClose()}
function orders(){
 const records=aggregateOrders();content.innerHTML=wrapper(`<div class="section-toolbar"><h1>Order Management</h1><input class="admin-search" data-order-search placeholder="Search orders…"><div class="admin-filters"><select data-order-type><option value="">All types</option><option>Vehicle</option><option>Investment</option><option>Stock</option></select></div></div><section class="admin-table-card"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>ORDER</th><th>TYPE</th><th>ITEM</th><th>CUSTOMER</th><th>AMOUNT</th><th>STATUS</th><th>DATE</th><th>ACTIONS</th></tr></thead><tbody data-order-rows></tbody></table></div></section>`);const renderRows=()=>{const q=content.querySelector("[data-order-search]").value.toLowerCase(),type=content.querySelector("[data-order-type]").value,rows=aggregateOrders().filter(o=>(o.id.toLowerCase().includes(q)||o.item.toLowerCase().includes(q))&&(!type||o.type===type));content.querySelector("[data-order-rows]").innerHTML=rows.length?rows.map(o=>`<tr><td class="table-title">${o.id}</td><td>${o.type}</td><td>${escapeHtml(o.item)}</td><td>${escapeHtml(o.customer)}</td><td>${money(o.amount)}</td><td>${status(displayStatus(o.status))}</td><td>${o.date?new Date(o.date).toLocaleDateString():"—"}</td><td><div class="table-actions"><button data-review-order="${o.id}">Review</button></div></td></tr>`).join(""):'<tr><td colspan="8"><div class="table-empty"><i>▣</i>No orders found.</div></td></tr>';content.querySelectorAll("[data-review-order]").forEach(b=>b.onclick=()=>orderModal(aggregateOrders().find(o=>o.id===b.dataset.reviewOrder)))};content.querySelector("[data-order-search]").oninput=renderRows;content.querySelector("[data-order-type]").onchange=renderRows;renderRows();
}
function displayStatus(s){return s==="Pending admin approval"?"Processing":s}
function orderModal(order){openModal(`Review ${order.id}`,`<div class="review-panel"><div class="review-grid"><div class="review-item"><span>Order type</span><strong>${order.type}</strong></div><div class="review-item"><span>Status</span><strong>${displayStatus(order.status)}</strong></div><div class="review-item"><span>Item</span><strong>${escapeHtml(order.item)}</strong></div><div class="review-item"><span>Amount</span><strong>${money(order.amount)}</strong></div><div class="review-item"><span>Customer</span><strong>${escapeHtml(order.customer)}</strong></div><div class="review-item"><span>Created</span><strong>${order.date?new Date(order.date).toLocaleString():"—"}</strong></div></div><label class="admin-field" style="margin-top:16px"><span>Update status</span><select data-order-status>${["Draft","Pending Deposit","Deposit Paid","Financing Active","Completed","Cancelled"].map(x=>`<option ${displayStatus(order.status)===x?"selected":""}>${x}</option>`)}</select></label><label class="admin-field" style="margin-top:12px"><span>Internal notes</span><textarea data-order-note placeholder="Add an operational note…"></textarea></label><div class="admin-form-actions"><button class="admin-secondary" data-modal-close>Close</button><button class="admin-primary" data-save-order>Save Status</button></div></div>`);modal.querySelector("[data-save-order]").onclick=()=>{updateOrder(order,modal.querySelector("[data-order-status]").value);audit("Updated order status",`${order.id} → ${modal.querySelector("[data-order-status]").value}`);closeModal();showToast("Order status updated");orders()};bindModalClose()}
function updateOrder(order,statusValue){if(order.type==="Vehicle"){const rows=get("vehicleOrders"),index=Number(order.id.split("-")[1])-1;if(rows[index])rows[index].status=statusValue;set("vehicleOrders",rows)}else{const rows=get(order.source);if(rows[order.sourceIndex])rows[order.sourceIndex].status=statusValue;set(order.source,rows)}}
function kyc(){
 const submission=JSON.parse(localStorage.getItem("kycSubmission")||"null"),users=getUsers();content.innerHTML=wrapper(`<div class="section-toolbar"><h1>KYC Review Queue</h1></div><section class="admin-table-card"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>SUBMISSION</th><th>CUSTOMER</th><th>STATUS</th><th>SUBMITTED</th><th>ACTIONS</th></tr></thead><tbody>${submission?`<tr><td class="table-title">KYC-001</td><td>${escapeHtml(users[0]?.name||"Current customer")}<div class="table-sub">${escapeHtml(users[0]?.email||"")}</div></td><td>${status(submission.status||"Pending")}</td><td>${new Date(submission.submittedAt).toLocaleString()}</td><td><div class="table-actions"><button data-review-kyc>Review</button></div></td></tr>`:'<tr><td colspan="5"><div class="table-empty"><i>◇</i>No KYC submissions waiting for review.</div></td></tr>'}</tbody></table></div></section>`);content.querySelector("[data-review-kyc]")?.addEventListener("click",()=>kycModal(submission));
}
function kycModal(submission){openModal("Review KYC Submission",`<div class="review-panel"><div class="admin-note">Demo documents are represented by the customer submission record. File storage will connect through the backend.</div><div class="review-grid" style="margin-top:16px"><div class="review-item"><span>Customer</span><strong>${escapeHtml(getUsers()[0]?.name||"Customer")}</strong></div><div class="review-item"><span>Submitted</span><strong>${new Date(submission.submittedAt).toLocaleString()}</strong></div><div class="review-item"><span>Government ID</span><strong>Document uploaded</strong></div><div class="review-item"><span>Selfie</span><strong>Image uploaded</strong></div></div><label class="admin-field" style="margin-top:15px"><span>Review notes</span><textarea data-kyc-note></textarea></label><div class="admin-form-actions"><button class="admin-danger" data-kyc-reject>Reject</button><button class="admin-secondary" data-kyc-resubmit>Request Resubmission</button><button class="admin-primary" data-kyc-approve>Approve KYC</button></div></div>`);const decide=decision=>{submission.status=decision;submission.reviewedBy=admin.email;submission.reviewedAt=new Date().toISOString();submission.notes=modal.querySelector("[data-kyc-note]").value;localStorage.setItem("kycSubmission",JSON.stringify(submission));const users=getUsers();if(users[0])users[0].kyc=decision;set(keys.users,users);audit(`${decision} KYC`,"KYC-001");closeModal();showToast(`KYC ${decision.toLowerCase()}`);kyc()};modal.querySelector("[data-kyc-approve]").onclick=()=>decide("Approved");modal.querySelector("[data-kyc-reject]").onclick=()=>decide("Rejected");modal.querySelector("[data-kyc-resubmit]").onclick=()=>decide("Resubmission Required")}
function payments(){
 const records=get(keys.payments);content.innerHTML=wrapper(`${toolbar("Payment Management","data-add-payment","Manual Entry")}<section class="metric-grid" style="margin-bottom:17px">${metric("Total Received",money(records.reduce((a,p)=>a+Number(p.amount),0)),"$","Recorded payments")}${metric("Pending Verification",records.filter(p=>p.status==="Pending").length,"⌛","Requires action")}${metric("Confirmed",records.filter(p=>p.status==="Confirmed").length,"✓","Verified payments")}${metric("Refunded",records.filter(p=>p.status==="Refunded").length,"↩","Processed refunds")}</section><section class="admin-table-card"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>PAYMENT</th><th>CUSTOMER</th><th>METHOD</th><th>AMOUNT</th><th>STATUS</th><th>DATE</th><th>ACTIONS</th></tr></thead><tbody>${records.map(p=>`<tr><td class="table-title">${p.id}</td><td>${escapeHtml(p.customer)}</td><td>${escapeHtml(p.method)}</td><td>${money(p.amount)}</td><td>${status(p.status)}</td><td>${new Date(p.date).toLocaleDateString()}</td><td><div class="table-actions"><button data-confirm-payment="${p.id}">Confirm</button><button data-refund-payment="${p.id}">Refund</button></div></td></tr>`).join("")||'<tr><td colspan="7"><div class="table-empty">No payments recorded.</div></td></tr>'}</tbody></table></div></section>`);content.querySelector("[data-add-payment]").onclick=paymentModal;content.querySelectorAll("[data-confirm-payment]").forEach(b=>b.onclick=()=>paymentStatus(b.dataset.confirmPayment,"Confirmed"));content.querySelectorAll("[data-refund-payment]").forEach(b=>b.onclick=()=>paymentStatus(b.dataset.refundPayment,"Refunded"));
}
function paymentModal(){openModal("Manual Payment Entry",`<form class="admin-form"><div class="admin-form-grid"><label class="admin-field"><span>Customer</span><input name="customer" required></label><label class="admin-field"><span>Amount</span><input name="amount" type="number" min=".01" step=".01" required></label><label class="admin-field"><span>Payment method</span><select name="method"><option>Bank Transfer</option><option>Card</option><option>Bitcoin</option><option>USDT</option><option>Manual Payment</option></select></label><label class="admin-field"><span>Status</span><select name="status"><option>Pending</option><option>Confirmed</option></select></label><label class="admin-field wide"><span>Reference / notes</span><textarea name="notes"></textarea></label></div><div class="admin-form-actions"><button type="button" class="admin-secondary" data-modal-close>Cancel</button><button class="admin-primary">Record Payment</button></div></form>`);const form=modal.querySelector("form");form.onsubmit=e=>{e.preventDefault();const rows=get(keys.payments),data=Object.fromEntries(new FormData(form));data.id=`PAY-${Date.now()}`;data.amount=Number(data.amount);data.date=new Date().toISOString();rows.unshift(data);set(keys.payments,rows);audit("Recorded manual payment",`${data.customer} • ${money(data.amount)}`);closeModal();showToast("Payment recorded");payments()};bindModalClose()}
function paymentStatus(id,value){const rows=get(keys.payments),p=rows.find(x=>x.id===id),wasConfirmed=p.status==="Confirmed";p.status=value;set(keys.payments,rows);if(value==="Confirmed"&&!wasConfirmed)localStorage.setItem("teslaWalletBalance",String(Number(localStorage.getItem("teslaWalletBalance")||0)+Number(p.amount||0)));audit(`${value} payment`,id);showToast(`Payment ${value.toLowerCase()}`);payments()}
function auditLog(){const logs=get(keys.audit);content.innerHTML=wrapper(`<div class="section-toolbar"><h1>Audit Log</h1><input class="admin-search" data-table-search placeholder="Search audit events…"><button class="admin-secondary" data-export>Export CSV</button></div><section class="admin-table-card"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>TIME</th><th>ADMIN</th><th>ACTION</th><th>TARGET</th><th>EVENT ID</th></tr></thead><tbody data-audit-rows></tbody></table></div></section>`);const renderRows=()=>{const q=content.querySelector("[data-table-search]").value.toLowerCase();content.querySelector("[data-audit-rows]").innerHTML=logs.filter(l=>(l.action+l.target).toLowerCase().includes(q)).map(l=>`<tr><td>${new Date(l.time).toLocaleString()}</td><td>${escapeHtml(l.admin)}</td><td class="table-title">${escapeHtml(l.action)}</td><td>${escapeHtml(l.target)}</td><td class="table-sub">${l.id.slice(0,12)}</td></tr>`).join("")};content.querySelector("[data-table-search]").oninput=renderRows;content.querySelector("[data-export]").onclick=()=>exportAudit(logs);renderRows()}
function exportAudit(logs){const csv=["Time,Admin,Action,Target",...logs.map(l=>[l.time,l.admin,l.action,l.target].map(x=>`"${String(x).replaceAll('"','""')}"`).join(","))].join("\n"),blob=new Blob([csv],{type:"text/csv"}),url=URL.createObjectURL(blob),a=document.createElement("a");a.href=url;a.download="tesla-admin-audit.csv";a.click();URL.revokeObjectURL(url);showToast("Audit log exported")}
function confirmDelete(type,id){const labels={vehicle:"vehicle",plan:"investment plan",user:"user"};openModal(`Delete ${labels[type]}`,`<div class="review-panel"><div class="admin-note">This action removes the record from the current design database.</div><h3>Are you sure you want to delete this ${labels[type]}?</h3><div class="admin-form-actions"><button class="admin-secondary" data-modal-close>Cancel</button><button class="admin-danger" data-confirm-delete>Delete permanently</button></div></div>`);modal.querySelector("[data-confirm-delete]").onclick=()=>{const key=type==="vehicle"?keys.vehicles:type==="plan"?keys.plans:keys.users,setRows=get(key).filter(x=>x.id!==id);set(key,setRows);audit(`Deleted ${labels[type]}`,id);closeModal();showToast(`${labels[type]} deleted`);({vehicle:vehicles,plan:plans,user:usersView})[type]()};bindModalClose()}
function openModal(heading,bodyHtml){modal.innerHTML=`<div class="admin-modal"><div class="admin-modal-head"><h2>${heading}</h2><button data-modal-close>×</button></div>${bodyHtml}</div>`;modal.hidden=false;bindModalClose()}
function closeModal(){modal.hidden=true;modal.innerHTML=""}
function bindModalClose(){modal.querySelectorAll("[data-modal-close]").forEach(b=>b.onclick=closeModal);modal.onclick=e=>{if(e.target===modal)closeModal()}}
function timeAgo(date){const seconds=Math.max(1,(Date.now()-new Date(date))/1000);if(seconds<60)return"Just now";if(seconds<3600)return`${Math.floor(seconds/60)}m ago`;if(seconds<86400)return`${Math.floor(seconds/3600)}h ago`;return`${Math.floor(seconds/86400)}d ago`}
function bindGo(){content.querySelectorAll("[data-go]").forEach(b=>b.onclick=()=>navigate(b.dataset.go))}
const renderers={overview,vehicles,plans,users:usersView,orders,kyc,payments,audit:auditLog};
function navigate(section){location.hash=section}
function render(){const section=location.hash.slice(1)||"overview";document.querySelectorAll(".admin-nav a").forEach(a=>a.classList.toggle("active",a.dataset.section===section));title.textContent={overview:"Overview",vehicles:"Vehicle Inventory",plans:"Investment Plans",users:"User Management",orders:"Order Management",kyc:"KYC Reviews",payments:"Payment Management",audit:"Audit Log"}[section]||"Overview";(renderers[section]||overview)();body.classList.remove("menu-open");scrollTo(0,0)}
document.querySelector("[data-admin-menu]").onclick=()=>body.classList.toggle("menu-open");document.querySelector("[data-admin-overlay]").onclick=()=>body.classList.remove("menu-open");document.querySelector("[data-admin-logout]").onclick=()=>{audit("Admin signed out",admin.email);localStorage.removeItem("stockprimeAdminSession");location.replace("admin-login.html")};document.querySelector("[data-admin-search]").onclick=()=>showToast("Use the search field inside each management section");document.querySelector("[data-admin-notifications]").onclick=()=>showToast("4 operational items require attention");addEventListener("hashchange",render);render();
})();

