(function(){
  const content=document.querySelector("#admin-content"),title=document.querySelector("[data-admin-title]"),toastElement=document.querySelector("[data-admin-toast]");
  const money=value=>Number(value||0).toLocaleString("en-US",{style:"currency",currency:"USD"});
  const escapeHtml=value=>String(value??"").replace(/[&<>"']/g,char=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[char]));
  const status=value=>`<span class="status-pill ${String(value).toLowerCase().replaceAll(" ","-")}">${escapeHtml(value)}</span>`;
  const toast=message=>{toastElement.textContent=message;toastElement.classList.add("show");setTimeout(()=>toastElement.classList.remove("show"),2500)};
  async function renderPayments(){
    if(location.hash!=="#payments")return;
    title.textContent="Payment Management";
    content.innerHTML='<div class="admin-container"><div class="section-toolbar"><h1>Payment Management</h1><input class="admin-search" data-payment-search placeholder="Search payments..."></div><section class="admin-table-card"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>PAYMENT</th><th>CUSTOMER</th><th>METHOD</th><th>AMOUNT</th><th>STATUS</th><th>DATE</th><th>ACTIONS</th></tr></thead><tbody data-payment-rows><tr><td colspan="7"><div class="table-empty">Loading payments...</div></td></tr></tbody></table></div></section></div>';
    try{
      const response=await fetch("/api/admin/payments",{credentials:"same-origin"}),data=await response.json();if(response.status===401){localStorage.removeItem("stockprimeAdminSession");location.replace("admin-login.html");return}if(response.status===404)throw new Error("Payments API is not loaded on the running server. Restart Node with npm start, then sign in again.");if(!response.ok)throw new Error(data.error||"Payments could not be loaded.");
      const rows=data.payments||[],tbody=content.querySelector("[data-payment-rows]"),search=content.querySelector("[data-payment-search]");
      const render=()=>{const q=search.value.toLowerCase(),filtered=rows.filter(payment=>(payment.id+payment.customer+payment.method+payment.reference).toLowerCase().includes(q));tbody.innerHTML=filtered.length?filtered.map(payment=>`<tr><td><div class="table-title">${escapeHtml(payment.id)}</div><div class="table-sub">${escapeHtml(payment.reference||"No reference")}</div></td><td>${escapeHtml(payment.customer_name||"Customer")}<div class="table-sub">${escapeHtml(payment.customer)}</div></td><td>${escapeHtml(payment.method||"Wallet")}</td><td>${money(Number(payment.amount_cents)/100)}</td><td>${status(payment.status)}</td><td>${new Date(payment.date).toLocaleString()}</td><td><div class="table-actions">${payment.status==="pending"?`<button data-payment-status="${escapeHtml(payment.id)}" data-status-value="confirmed">Confirm</button><button data-payment-status="${escapeHtml(payment.id)}" data-status-value="rejected">Reject</button>`:""}</div></td></tr>`).join(""):'<tr><td colspan="7"><div class="table-empty">No deposit payments found.</div></td></tr>';tbody.querySelectorAll("[data-payment-status]").forEach(button=>button.onclick=()=>updatePayment(button.dataset.paymentStatus,button.dataset.statusValue))};
      search.oninput=render;render();
    }catch(error){toast(error.message)}
  }
  async function updatePayment(id,value){
    try{
      let response=await fetch(`/api/admin/payments/${encodeURIComponent(id)}/status`,{method:"POST",headers:{"Content-Type":"application/json"},credentials:"same-origin",body:JSON.stringify({status:value})}),data=await response.json();
      if(response.status===404){response=await fetch("/api/admin/payments/status",{method:"POST",headers:{"Content-Type":"application/json"},credentials:"same-origin",body:JSON.stringify({paymentId:id,status:value})});data=await response.json()}
      if(response.status===404)throw new Error("Payments API is not loaded on the running server. Restart Node with npm start, then sign in again.");if(!response.ok)throw new Error(data.error||"Payment could not be updated.");
      toast(data.message);renderPayments();
    }catch(error){toast(error.message)}
  }
  addEventListener("hashchange",()=>setTimeout(renderPayments,0));if(location.hash==="#payments")setTimeout(renderPayments,0);
})();
